            </div>
          </transition>
      </div>
    </div>

    <!-- Mobile View -->
    <div class="mobile-agent-section">
      <div 
        class="mobile-scroll-container"
        ref="scrollContainer"
        @scroll="handleScroll"
      >
        <div 
          v-for="(tab, index) in tabs" 
          :key="index" 
          class="mobile-card"
        >
