<script setup>
import { ref } from 'vue'
import { useData } from 'vitepress'

const activeTab = ref(0)
const { isDark } = useData()
const scrollContainer = ref(null)

const tabs = [
  {
    title: 'Agent 智能代理',
    description: 'Agent自主规划，自动完成复杂任务（可以基于日志回滚）',
    img: {
      light: '/images/smart-agent-light-zh.webp',
      dark: '/images/smart-agent-dark-zh.webp'
    }
  },
  {
    title: '智能命令补全',
    description: '基于个人操作习惯的，跨服务器，跨平台智能命令补全',
    img: {
      light: '/images/command-completion-light.webp',
      dark: '/images/command-completion-dark.webp'
    }
  },
  {
    title: '语音输入控制',
    description: '移动环境下，使用语音代替键盘输入，提高远程操作效率',
    img: {
      light: '/images/voice-input-light-zh.webp',
      dark: '/images/voice-input-dark-zh.webp'
    }
  }
]
let hoverTimer = null
const switchTab = (index) => {
  clearTimeout(hoverTimer)
  hoverTimer = setTimeout(() => {
    activeTab.value = index
  }, 200)
}

const scrollToTab = (index) => {
  activeTab.value = index
  if (scrollContainer.value) {
    const width = scrollContainer.value.clientWidth
    scrollContainer.value.scrollTo({
      left: width * index,
      behavior: 'smooth'
    })
  }
}

const handleScroll = () => {
  if (!scrollContainer.value) return
  
  const scrollLeft = scrollContainer.value.scrollLeft
  const width = scrollContainer.value.clientWidth
  const newIndex = Math.round(scrollLeft / width)
  
  if (newIndex !== activeTab.value && newIndex >= 0 && newIndex < tabs.length) {
    activeTab.value = newIndex
  }
}
</script>

